function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // 1. Collect unique weights to determine candidate thresholds
    const weights = new Set();
    for (const [, , w] of edges) {
        weights.add(w);
    }

    // Candidate thresholds C = {0} U {all unique weights}
    let candidates = [0];
    weights.forEach(w => candidates.push(w));

    // Sort candidates
    candidates.sort((a, b) => a - b);

    // Build adjacency list representation of the graph
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        // Undirected graph
        adj[u].push({ neighbor: v, weight: w });
        adj[v].push({ neighbor: u, weight: w });
    }

    /**
     * Checks if there exists a path from source to target using at most k heavy edges, 
     * given the threshold T. Uses 0-1 BFS.
     * @param {number} T - The threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (T) => {
        // D[i]: minimum number of heavy edges to reach node i
        const D = Array(n).fill(Infinity);
        D[source] = 0;

        // Deque simulation using an array and head pointer. 
        // Nodes reachable via 0-cost edges are pushed to the front (unshift conceptually).
        // Nodes reachable via 1-cost edges are pushed to the back (push).
        const deque = [source]; 
        let head = 0;

        while(head < deque.length) {
            const u = deque[head++];

            if (u === target && D[u] <= k) {
                 // Since 0-1 BFS finds the shortest path (in terms of heavy edges) first,
                 // if we reach the target and its cost is acceptable, we can potentially stop early.
                 // However, letting it run ensures correctness if other paths might relax D[target] 
                 // further down the line, but since we only care about the final D[target], 
                 // we let it complete or check the final value.
            }

            if (D[u] > k) {
                // Optimization: if the current minimum path to u already exceeds k, 
                // any extension will also exceed k.
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const w = edge.weight;

                // Cost calculation: 1 if heavy (w > T), 0 if light (w <= T)
                const cost = (w > T) ? 1 : 0;

                const newCost = D[u] + cost;

                if (newCost < D[v]) {
                    D[v] = newCost;

                    // 0-1 BFS logic:
                    if (cost === 0) {
                        // 0-cost edges are prioritized (conceptually prepended)
                        deque.unshift(v); 
                    } else {
                        // 1-cost edges are appended
                        deque.push(v); 
                    }
                }
            }
        }

        return D[target] <= k;
    };

    // 3. Binary Search over candidate thresholds
    let L = 0;
    let R = candidates.length - 1;
    let result = -1;

    while (L <= R) {
        const midIndex = Math.floor((L + R) / 2);
        const T = candidates[midIndex];

        if (canReach(T)) {
            // T works. Store it as a potential answer and try for a smaller threshold.
            result = T;
            R = midIndex - 1; 
        } else {
            // T does not work. We need a larger threshold to potentially make more edges light.
            L = midIndex + 1; 
        }
    }

    return result;
}

